def validate_url(url):
    regex = re.compile(
        r'^https?://'  # http:// or https://
        r'((([A-Za-z0-9-]+)\.)+([A-Za-z]{2,63}))'  # subdomain
        r'(/.*)?'  # path
    )
    if re.match(regex, url):
        return True
    return False

